insert into meeting_decisions (decided_date,fiscal_year,category,title,detail,owner,source_meeting_id,sort_order) values
('2021-07-30'::date,110,'系統/工程','主管會議每週固定召開','本會議原則每週一舉行，討論溝通跨所、跨部門各種事務。','雷皓明',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2021-07-30' limit 1),1000),
('2021-08-09'::date,110,'系統/工程','跨所/跨部門通報窗口','跨所→雷；行政/總務/人資→emily；跨部門及專案系統→泓儒；知識管理→黃杰。週四前提討論項目、週五出大綱、週一開會。','雷皓明',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2021-08-09' limit 1),1001),
('2021-08-30'::date,110,'系統/工程','檔案命名規則定案','收發文/閱卷/出狀統一命名「當事人_日期_文書內容」；各分所建立總收文制度。','吳泰儀',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2021-08-30' limit 1),1002),
('2021-09-06'::date,110,'獎金制度','法扶自接案拆分調整','法扶案件事務所抽成由對半改為事務所 40%、同仁 60%（因稅費由個人負擔）。','飛宇',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2021-09-06' limit 1),1003),
('2021-10-04'::date,110,'委前進線','侵害配偶權共同被告委任原則','承認外遇→兩邊都接同一律師；不承認→只接一個、另一個轉出；即便不認仍可一起諮詢。','黃杰',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2021-10-04' limit 1),1004),
('2021-11-08'::date,110,'委後/客戶','律師不再做見證、改法務證人','律師不做離婚見證，改由法務擔任證人，地點在事務所；文件「見證人」一律改「證人」。','黃杰',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2021-11-08' limit 1),1005),
('2021-11-08'::date,110,'委前進線','客服信箱分流 service@zhelu.tw','對造律師信→轉承辦cc主管；法顧→客戶關係；民眾→委前預約；求職→人資 hr@。',null,(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2021-11-08' limit 1),1006),
('2021-11-22'::date,110,'委後/客戶','律師證人收費','文章只寫「證人」；律師證人一位兩萬；原則不外出、例外加價。','雷皓明',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2021-11-22' limit 1),1007),
('2021-12-20'::date,110,'委前進線','利益衝突處理流程公告','同仁發現利衝風險→提報主管律師判斷（必要時提主管會議）；主管律師決定退款與否、轉接案部門紹成處理。（2021/12/26 公告）','雷皓明',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2021-12-20' limit 1),1008),
('2021-12-20'::date,110,'委後/客戶','離婚證人獎金制度','改由法務同仁擔任離婚證人，每次 1000 元證人獎金。（2021/12/26 公告）','林杰',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2021-12-20' limit 1),1009),
('2021-12-20'::date,110,'系統/工程','主管會議公告流程定案','會後 24H 內在 LINE 群公告＋記事本＋雲端【公告_管理】＋公告表單登錄時程標題。（2021/12/26 公告）','雷皓明',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2021-12-20' limit 1),1010),
('2022-01-03'::date,111,'系統/工程','結案流程表正式上路','將案件分類設計結案流程表，結案時印出核對、依表完成後歸入紙本卷。','雷皓明',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2022-01-03' limit 1),1011),
('2022-01-10'::date,111,'系統/工程','案件關鍵字 tag 系統上線','案件可建關鍵字並搜尋；各部門律師標記新舊案，最晚於結案時 tag。','何泓儒',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2022-01-10' limit 1),1012),
('2022-01-24'::date,111,'系統/工程','新增「舊喆律部門」','舊喆律案件獨立為新部門處理結案流程。','何泓儒',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2022-01-24' limit 1),1013),
