('2022-04-11'::date,111,'委前進線','強執與假扣押分開報價','強制執行 3-5 萬、假扣押裁定 2 萬＋執行 3-5 萬；分開報價避免強執比假扣押便宜。','雷皓明',(select id from meetings where meeting_type='mgmt_weekly' and meeting_date='2022-04-11' limit 1),1015),
